import math
import numpy as np
def dist_to_line(cent_x, cent_y, f, line_e01, line_e02, line_e03, line_e12, line_e13, line_e23, pp_x, pp_y):
	cent_local = np.zeros(16)
	cent_local[11] = (-f) # e0 ^ (e1 ^ e2)
	cent_local[12] = cent_y - pp_y # e0 ^ (e1 ^ e3)
	cent_local[13] = (-(cent_x - pp_x)) # e0 ^ (e2 ^ e3)
	plane_representing_dist = np.zeros(16)
	plane_representing_dist[2] = (-(line_e01 * math.sqrt((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23)))) / math.sqrt(((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23)))) * ((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23))))) + (-(cent_local[12] * line_e12 * math.sqrt((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23)))) / math.sqrt(((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23)))) * ((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23))))))) + (-cent_local[11]) * (-(line_e13 * math.sqrt((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23)))) / math.sqrt(((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23)))) * ((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23))))))))) # e1
	plane_representing_dist[3] = (-(line_e02 * math.sqrt((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23)))) / math.sqrt(((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23)))) * ((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23))))))) + (-((-cent_local[13]) * line_e12 * math.sqrt((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23)))) / math.sqrt(((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23)))) * ((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23))))))) + (-cent_local[11]) * line_e23 * math.sqrt((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23)))) / math.sqrt(((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23)))) * ((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23))))) # e2
	plane_representing_dist[4] = (-(line_e03 * math.sqrt((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23)))) / math.sqrt(((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23)))) * ((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23))))) + (-((-cent_local[13]) * (-(line_e13 * math.sqrt((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23)))) / math.sqrt(((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23)))) * ((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23))))))))) + cent_local[12] * line_e23 * math.sqrt((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23)))) / math.sqrt(((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23)))) * ((-(line_e12 * (-line_e12))) + (-(line_e13 * (-line_e13))) + (-(line_e23 * (-line_e23))))))) # e3
	dist = np.zeros(16)
	dist[0] = math.sqrt(plane_representing_dist[2] * plane_representing_dist[2] + plane_representing_dist[3] * plane_representing_dist[3] + plane_representing_dist[4] * plane_representing_dist[4]) # 1.0
	return dist
